html = r'''<!doctype html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1, user-scalable=no">
<title>Signed Extrusion Pop-up Sketcher</title>
<style>
  :root {
    --bg: #f6f3ea;
    --panel: #fffdf6;
    --ink: #17202a;
    --cut: #111;
    --mountain: #c0392b;
    --valley: #2874a6;
    --soft: #777;
  }
  html, body {
    margin: 0;
    height: 100%;
    overflow: hidden;
    font: 14px/1.35 -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
    background: var(--bg);
    color: var(--ink);
  }
  #app {
    display: grid;
    grid-template-rows: auto 1fr;
    height: 100%;
  }
  header {
    padding: 8px 10px;
    background: #252525;
    color: white;
    display: flex;
    gap: 10px;
    align-items: center;
    flex-wrap: wrap;
  }
  header button, header select {
    font: inherit;
    padding: 5px 8px;
    border-radius: 8px;
    border: 1px solid #999;
    background: white;
    color: #111;
  }
  header label {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    white-space: nowrap;
  }
  header input[type=range] {
    width: 120px;
  }
  main {
    display: grid;
    grid-template-columns: 1fr 1fr;
    min-height: 0;
  }
  section {
    min-width: 0;
    min-height: 0;
    position: relative;
    border-right: 1px solid #ccc;
