  #view3d {
    width: 100%;
    height: 100%;
    display: block;
    background: linear-gradient(#fdfbf3, #e9e1cf);
    touch-action: none;
  }
  .legend {
    position: absolute;
    left: 10px;
    bottom: 8px;
    background: rgba(255,255,255,0.82);
    padding: 6px 8px;
    border-radius: 8px;
    font-size: 12px;
  }
  .swatch {
    display: inline-block;
    width: 18px;
