const dataEl = document.getElementById("data");
const statusEl = document.getElementById("status");
const pattern = document.getElementById("pattern");
const canvas = document.getElementById("view3d");
const ctx = canvas.getContext("2d");

function pretty(obj) {
  return JSON.stringify(obj, null, 2);
}

function setExample(obj) {
  design = structuredClone(obj);
  dataEl.value = pretty(design);
  renderAll();
}

function parseData() {
  let obj;
  try {
    obj = JSON.parse(dataEl.value);
  } catch (e) {
    return {ok:false, error:"JSON parse error: " + e.message};
  }
  const err = validate(obj);
  if (err) return {ok:false, error:err};
  design = obj;
  return {ok:true};
}

function validate(d) {
  if (!d || !Array.isArray(d.widths) || !Array.isArray(d.strips)) {
    return "Expected { widths: [...], strips: [[...], ...] }";
  }
  if (d.widths.length !== d.strips.length) {
    return "widths.length must equal strips.length.";
  }
  if (!d.widths.every(x => Number.isFinite(x) && x > 0)) {
    return "Every width must be a positive number.";
  }
  let totals = [];
  for (let i=0; i<d.strips.length; i++) {
    const s = d.strips[i];
    if (!Array.isArray(s) || s.length < 1) return "Every strip must be a non-empty length array.";
    if (!s.every(x => Number.isFinite(x) && x >= 0)) return "Every strip length must be a non-negative number.";
    totals.push(sum(s));
  }
  const t0 = totals[0];
  const maxDiff = Math.max(...totals.map(t => Math.abs(t - t0)));
  if (maxDiff > 1e-6) {
    return "Invariant violation: strip totals differ. Totals = [" + totals.map(x => x.toFixed(3)).join(", ") + "]";
  }
  if (t0 <= 0) return "Total paper length must be positive.";
  return "";
}

function normaliseStripTotals() {
  const r = parseData();
  if (!r.ok) {
    showStatus(r.error, true);
    return;
  }
  const totals = design.strips.map(sum);
  const target = Math.max(...totals);
  design.strips = design.strips.map((s, i) => {
    const extra = target - totals[i];
    if (extra > 1e-9) return s.concat([extra]);
    return s;
  });
  dataEl.value = pretty(design);
  renderAll();
}

function sum(a) { return a.reduce((x,y)=>x+y,0); }

function cumulative(a) {
  const out = [0];
  for (const x of a) out.push(out[out.length-1] + x);
  return out;
}

function showStatus(msg, bad=false) {
  statusEl.className = bad ? "bad" : "";
  statusEl.textContent = msg;
}

function renderAll() {
  const err = validate(design);
  if (err) {
    showStatus(err, true);
    return;
  }
  const totalW = sum(design.widths);
  const totalL = sum(design.strips[0]);
  showStatus(`OK. N=${design.widths.length} strips, width=${totalW.toFixed(3)}, paper length=${totalL.toFixed(3)}. 3D is fixed at 90°.`);
  drawPattern();
  draw3D();
}

function resize() {
  const rect = canvas.getBoundingClientRect();
  const dpr = window.devicePixelRatio || 1;
  canvas.width = Math.max(1, Math.floor(rect.width * dpr));
  canvas.height = Math.max(1, Math.floor(rect.height * dpr));
  ctx.setTransform(dpr,0,0,dpr,0,0);
  renderAll();
}

function drawPattern() {
  const r = pattern.getBoundingClientRect();
  const width = r.width, height = r.height;
  pattern.setAttribute("viewBox", `0 0 ${width} ${height}`);
  pattern.innerHTML = "";

  const totalW = sum(design.widths);
  const totalL = sum(design.strips[0]);
  const margin = 38;
  const s = Math.min((width - 2*margin)/totalW, (height - 2*margin)/totalL);
  const ox = (width - totalW*s)/2;
  const oy = (height - totalL*s)/2;

  function el(name) { return document.createElementNS("http://www.w3.org/2000/svg", name); }
  function line(x1,y1,x2,y2, stroke, dash="", lw=1.5) {
    const e = el("line");
    e.setAttribute("x1",x1); e.setAttribute("y1",y1);
    e.setAttribute("x2",x2); e.setAttribute("y2",y2);
    e.setAttribute("stroke",stroke);
    e.setAttribute("stroke-width",lw);
    e.setAttribute("stroke-linecap","round");
    if (dash) e.setAttribute("stroke-dasharray",dash);
    pattern.appendChild(e);
  }
  function rect(x,y,w,h,fill,stroke="#ddd",lw=1) {
    const e = el("rect");
    e.setAttribute("x",x); e.setAttribute("y",y);
    e.setAttribute("width",w); e.setAttribute("height",h);
    e.setAttribute("fill",fill);
    e.setAttribute("stroke",stroke);
    e.setAttribute("stroke-width",lw);
    pattern.appendChild(e);
  }
  function text(x,y,t) {
    const e = el("text");
    e.setAttribute("x",x); e.setAttribute("y",y);
    e.setAttribute("font-size","11");
    e.setAttribute("fill","#555");
    e.textContent = t;
    pattern.appendChild(e);
  }

  // Page outline
  rect(ox, oy, totalW*s, totalL*s, "#fffefb", "#999", 1.5);

  let x = ox;
  for (let i=0; i<design.widths.length; i++) {
    const w = design.widths[i] * s;
    const strip = design.strips[i];
    const cs = cumulative(strip);

    // shaded signed regions
    for (let j=0; j<strip.length; j++) {
      const y0 = oy + cs[j] * s;
      const h = strip[j] * s;
      const pos = (j % 2) === 0;
      rect(x, y0, w, h, pos ? "rgba(46,134,193,.13)" : "rgba(192,57,43,.11)", "none", 0);
    }

    // folds along this strip
    for (let j=1; j<cs.length-1; j++) {
      const y = oy + cs[j] * s;
      line(x, y, x+w, y, "#2874a6", "6 5", 1.4);
    }

    // cut / strip boundary
    line(x, oy, x, oy + totalL*s, "#111", "", i===0 ? 2.0 : 1.4);
    x += w;
  }
  line(x, oy, x, oy + totalL*s, "#111", "", 2.0);

  // top/bottom
  line(ox, oy, ox + totalW*s, oy, "#111", "", 1.5);
  line(ox, oy + totalL*s, ox + totalW*s, oy + totalL*s, "#111", "", 1.5);

  text(ox, oy - 8, "flat strip pattern: vertical boundaries are cuts; internal horizontal lines are folds");
}

function stripXPositions() {
  const xs = [0];
  for (const w of design.widths) xs.push(xs[xs.length-1] + w);
  const totalW = xs[xs.length-1];
  return xs.map(x => x - totalW/2);
}

function buildQuads() {
  const xs = stripXPositions();
  const quads = [];

  for (let i=0; i<design.strips.length; i++) {
    const x0 = xs[i], x1 = xs[i+1];
    const strip = design.strips[i];
    const cs = cumulative(strip);
    let prevY = 0;

    for (let j=0; j<strip.length; j++) {
      const L = strip[j];
      const sign = (j % 2) === 0 ? +1 : -1;
      const y = sign * depthScale * L;
      const z0 = cs[j], z1 = cs[j+1];

      // horizontal connector quad at the fold before this segment
      // This makes sign changes explicit as 90-degree bends.
      if (Math.abs(y - prevY) > 1e-9) {
        quads.push({
          pts: [[x0,prevY,z0],[x1,prevY,z0],[x1,y,z0],[x0,y,z0]],
          kind: "connector",
          sign: Math.sign(y - prevY)
        });
      }

      // signed vertical quad for this segment
      if (L > 1e-9) {
        quads.push({
          pts: [[x0,y,z0],[x1,y,z0],[x1,y,z1],[x0,y,z1]],
          kind: "signed",
          sign
        });
      }

      prevY = y;
    }

    // top connector back to the central backing plane
    const zEnd = cs[cs.length-1];
    if (Math.abs(prevY) > 1e-9) {
      quads.push({
        pts: [[x0,prevY,zEnd],[x1,prevY,zEnd],[x1,0,zEnd],[x0,0,zEnd]],
        kind: "connector",
        sign: -Math.sign(prevY)
      });
    }
  }

  // backing plane y=0, behind the strips
  const xMin = xs[0], xMax = xs[xs.length-1];
  const totalL = sum(design.strips[0]);
  quads.push({
    pts: [[xMin,0,0],[xMax,0,0],[xMax,0,totalL],[xMin,0,totalL]],
    kind: "backing",
    sign: 0
  });

  return quads;
}

function rotatePoint(p, rx, ry) {
  let [x,y,z] = p;
  // centre z for nicer orbit
  z -= sum(design.strips[0]) / 2;

  // rotate about X
  let c = Math.cos(rx), s = Math.sin(rx);
  let y1 = y*c - z*s;
  let z1 = y*s + z*c;
  y = y1; z = z1;

  // rotate about Z/up-ish axis, actually y-axis in model
  c = Math.cos(ry); s = Math.sin(ry);
  let x1 = x*c + z*s;
  let z2 = -x*s + z*c;
  x = x1; z = z2;

  return [x,y,z];
}

function project(p) {
  const r = canvas.getBoundingClientRect();
  const q = rotatePoint(p, cam.rx, cam.ry);
  const persp = 650 / (650 + q[2]*cam.zoom*0.035);
  return [
    r.width/2 + cam.panX + q[0]*cam.zoom*persp,
    r.height/2 + cam.panY - q[1]*cam.zoom*persp,
    q[2]
  ];
}

function drawPoly(pts, fill, stroke="#222", lw=1.1) {
  const ps = pts.map(project);
  ctx.beginPath();
  ctx.moveTo(ps[0][0], ps[0][1]);
  for (let i=1; i<ps.length; i++) ctx.lineTo(ps[i][0], ps[i][1]);
  ctx.closePath();
  ctx.fillStyle = fill;
  ctx.fill();
  ctx.strokeStyle = stroke;
  ctx.lineWidth = lw;
  ctx.stroke();
}

function draw3D() {
  const r = canvas.getBoundingClientRect();
  ctx.clearRect(0,0,r.width,r.height);

  let quads = buildQuads();
  quads.forEach(q => {
    q.depth = q.pts.reduce((acc,p) => acc + rotatePoint(p, cam.rx, cam.ry)[2], 0) / q.pts.length;
  });
  quads.sort((a,b) => a.depth - b.depth);

  for (const q of quads) {
    let fill;
    if (q.kind === "backing") fill = "rgba(255,255,250,.58)";
    else if (q.kind === "connector") fill = "rgba(230,226,210,.75)";
    else fill = q.sign > 0 ? "rgba(46,134,193,.72)" : "rgba(192,57,43,.66)";
    drawPoly(q.pts, fill, "#202020", q.kind === "backing" ? 1.0 : 1.25);
  }

  // visual note
  ctx.fillStyle = "rgba(0,0,0,.58)";
  ctx.font = "12px -apple-system, BlinkMacSystemFont, sans-serif";
  ctx.fillText("Fixed 90° state. Mesh is generated directly from strip widths and alternating signed lengths.", 10, r.height - 12);
}

// Interaction
let pointers = new Map();
let lastSingle = null;
let lastPinch = null;

canvas.addEventListener("pointerdown", ev => {
  canvas.setPointerCapture(ev.pointerId);
  pointers.set(ev.pointerId, {x:ev.clientX, y:ev.clientY});
  if (pointers.size === 1) lastSingle = {x:ev.clientX, y:ev.clientY};
  if (pointers.size === 2) lastPinch = pinchState();
});
canvas.addEventListener("pointermove", ev => {
  if (!pointers.has(ev.pointerId)) return;
  pointers.set(ev.pointerId, {x:ev.clientX, y:ev.clientY});

  if (pointers.size === 1 && lastSingle) {
    const p = [...pointers.values()][0];
    const dx = p.x - lastSingle.x;
    const dy = p.y - lastSingle.y;
    cam.ry += dx * 0.008;
    cam.rx += dy * 0.008;
    cam.rx = Math.max(-1.5, Math.min(1.5, cam.rx));
    lastSingle = {x:p.x, y:p.y};
    draw3D();
  } else if (pointers.size === 2 && lastPinch) {
    const now = pinchState();
    cam.zoom *= now.dist / Math.max(1, lastPinch.dist);
    cam.zoom = Math.max(25, Math.min(260, cam.zoom));
    cam.panX += now.cx - lastPinch.cx;
    cam.panY += now.cy - lastPinch.cy;
    lastPinch = now;
    draw3D();
  }
});
canvas.addEventListener("pointerup", endPointer);
canvas.addEventListener("pointercancel", endPointer);

function endPointer(ev) {
  pointers.delete(ev.pointerId);
  lastSingle = pointers.size === 1 ? {...[...pointers.values()][0]} : null;
  lastPinch = pointers.size === 2 ? pinchState() : null;
}

function pinchState() {
  const ps = [...pointers.values()];
  const a = ps[0], b = ps[1];
  const dx = b.x-a.x, dy = b.y-a.y;
  return {
    dist: Math.hypot(dx,dy),
    cx: (a.x+b.x)/2,
    cy: (a.y+b.y)/2
  };
}

// Buttons
document.getElementById("ex1").addEventListener("click", () => setExample(exampleA));
document.getElementById("ex2").addEventListener("click", () => setExample(exampleB));
document.getElementById("apply").addEventListener("click", () => {
  const r = parseData();
  if (!r.ok) showStatus(r.error, true);
  else renderAll();
});
document.getElementById("normalise").addEventListener("click", normaliseStripTotals);
document.getElementById("depth").addEventListener("input", ev => {
  depthScale = Number(ev.target.value);
  document.getElementById("depthText").textContent = depthScale.toFixed(2);
  draw3D();
});

window.addEventListener("resize", resize);
dataEl.value = pretty(design);
resize();
</script>
</body>
</html>
