<script>
"use strict";

/*
  Signed Strip Pop-up — 90° coordinate model
  ------------------------------------------

  Flat paper coordinates:
    x in [0, W]
    y in [-H, H]
    origin = left edge, halfway up the paper
    paper size = W by 2H

  90° folded backing sheet:
    upper half, y >= 0:  (X,Y,Z) = (x, y, 0)
    lower half, y <= 0:  (X,Y,Z) = (x, 0, -y)
    therefore the lower edge y=-H is at z=H.

  Strip data:
    widths: [w_i]
    strips[i]: [l_i1, l_i2, ...]
    sum_j l_ij must be 2H for every strip.
    Each strip begins at flat y=-H, hence in 3D at z=H.

  Mesh convention for the signed pop-up strip:
    Let t run along the strip from 0 to 2H, starting at the lower edge.
    In 90° coordinates, the run coordinate is z = H - t.
    The j-th length interval occupies z in [H-cum[j], H-cum[j+1]].
    Its sign alternates +, -, +, - from j=0.

    This app renders each interval as a horizontal quad at signed height
      Y = sign * heightScale * length
    plus vertical connector quads at fold boundaries. The backing sheet is
    rendered literally as the two 90° half-sheets.

  So: the coordinate convention and "start at z=H" are literal. The remaining
  modelling choice is how signed lengths determine the height of the pop-up
  interval. That is concentrated in signedHeight(length, sign).
*/

const exampleA = {
  widths: [1, 1, 1, 1, 1, 1],
  strips: [
