<script>
"use strict";

/*
  Alternating 90-degree strip model
  ---------------------------------

  Flat paper coordinates:
    x in [0,W]
    y in [-H,H]
    origin line is the main fold y=0.

  Folded backing sheet:
    lower half y in [-H,0] -> horizontal plane Y=0, Z=-y
    upper half y in [0,H]  -> vertical plane   Y=y, Z=0

  Therefore the lower edge y=-H is at z=H.

  Strip rule:
    For strip i with lengths [l1,l2,l3,...]:

      start at (Y,Z) = (0,H)

      l1: horizontal in Y=0,  Z decreases by l1
      l2: vertical   in fixed Z, Y increases by l2
      l3: horizontal in fixed Y, Z decreases by l3
      l4: vertical   in fixed Z, Y increases by l4
      ...

    Invariants for a strip to connect the lower edge to the upper edge:
      sum(odd-position lengths: l1,l3,l5,...) = H
      sum(even-position lengths: l2,l4,l6,...) = H

    The flat paper length of each strip is still 2H.

  The 3D mesh is made by extruding each segment across the corresponding strip
  width in x. This is the literal quad mesh implied by the alternating rule.
*/

const examples = {
  folded: {
    widths: [1, 1, 1, 1, 1, 1],
    strips: [
      [2, 2],
      [2, 2],
      [2, 2],
      [2, 2],
      [2, 2],
      [2, 2]
    ]
  },

  step: {
    widths: [1.2, 1.6, 1.2],
    strips: [
      [2, 2],              // uncut left side: just folded page
      [0.85, 0.9, 1.15, 1.1], // central pop-up step/cuboid cross-section
      [2, 2]               // uncut right side
    ]
  },

  richA: {
    widths: [0.8, 1, 1, 1, 1, 0.8],
    strips: [
      [2, 2],
      [1.3, 0.5, 0.7, 1.5],
      [0.9, 1.1, 1.1, 0.9],
      [0.55, 1.35, 1.45, 0.65],
      [1.1, 0.8, 0.9, 1.2],
      [2, 2]
    ]
  },

  richB: {
    widths: [0.7, 0.9, 1.0, 1.0, 0.9, 0.7],
    strips: [
      [2, 2],
      [0.8, 0.6, 0.55, 0.7, 0.65, 0.7],
      [0.55, 1.0, 0.95, 0.45, 0.5, 0.55],
      [0.55, 0.45, 0.95, 1.0, 0.5, 0.55],
      [0.8, 0.7, 0.55, 0.6, 0.65, 0.7],
      [2, 2]
    ]
  }
};

let design = structuredClone(examples.step);
let cam = { rx: -0.62, ry: 0.74, zoom: 100, panX: 0, panY: 0 };

const panes = document.getElementById("panes");
const dataEl = document.getElementById("data");
const statusEl = document.getElementById("status");
const pattern = document.getElementById("pattern");
const canvas = document.getElementById("view3d");
const ctx = canvas.getContext("2d");

function pretty(obj) { return JSON.stringify(obj, null, 2); }
function sum(a) { return a.reduce((x,y)=>x+y,0); }
function cumulative(a) {
  const out = [0];
  for (const x of a) out.push(out[out.length-1] + x);
  return out;
}

function horizSum(strip) {
  let s = 0;
  for (let j=0; j<strip.length; j += 2) s += strip[j];
  return s;
}

function vertSum(strip) {
  let s = 0;
  for (let j=1; j<strip.length; j += 2) s += strip[j];
  return s;
}

function paperParams() {
  // For a valid strip, horizontal sum and vertical sum are both H.
  const H = horizSum(design.strips[0]);
  const W = sum(design.widths);
  return { W, H, twoH: 2*H };
}

function validate(d) {
  if (!d || !Array.isArray(d.widths) || !Array.isArray(d.strips)) {
    return "Expected { widths: [...], strips: [[...], ...] }";
  }
  if (d.widths.length !== d.strips.length) {
    return "widths.length must equal strips.length.";
  }
  if (!d.widths.every(x => Number.isFinite(x) && x > 0)) {
    return "Every width must be a positive number.";
  }
  if (d.strips.length === 0) return "Need at least one strip.";

  const H0 = horizSum(d.strips[0]);
  const V0 = vertSum(d.strips[0]);
  if (H0 <= 0 || V0 <= 0) return "The first strip must have positive horizontal and vertical sums.";
  if (Math.abs(H0 - V0) > 1e-6) {
    return `First strip must end on the upper edge: horizontal sum ${H0.toFixed(3)} must equal vertical sum ${V0.toFixed(3)}.`;
  }

  for (let i=0; i<d.strips.length; i++) {
    const strip = d.strips[i];
    if (!Array.isArray(strip) || strip.length < 2) {
      return "Every strip needs at least [horizontal, vertical].";
    }
    if (!strip.every(x => Number.isFinite(x) && x >= 0)) {
      return "Every strip length must be non-negative.";
    }
    const hs = horizSum(strip);
    const vs = vertSum(strip);
    if (Math.abs(hs - H0) > 1e-6 || Math.abs(vs - H0) > 1e-6) {
      return `Strip ${i} violates endpoint invariants: horizontal sum ${hs.toFixed(3)}, vertical sum ${vs.toFixed(3)}, expected both ${H0.toFixed(3)}.`;
    }
  }
  return "";
}

function parseData() {
  let obj;
  try { obj = JSON.parse(dataEl.value); }
  catch(e) { return {ok:false, error:"JSON parse error: " + e.message}; }
  const err = validate(obj);
  if (err) return {ok:false, error:err};
  design = obj;
  return {ok:true};
}

function setExample(name) {
  design = structuredClone(examples[name]);
  dataEl.value = pretty(design);
  renderAll();
}

function showStatus(msg, bad=false) {
  statusEl.className = bad ? "bad" : "";
  statusEl.textContent = msg;
}

function renderAll() {
  const err = validate(design);
  if (err) {
    showStatus(err, true);
    return;
  }
  const {W,H} = paperParams();
  showStatus(`OK. W=${W.toFixed(3)}, H=${H.toFixed(3)}. Every strip starts at lower edge y=-H → z=H, alternates horizontal/vertical, and ends at upper edge y=H → z=0.`);
  drawPattern();
  draw3D();
}

function resize() {
  const rect = canvas.getBoundingClientRect();
  const dpr = window.devicePixelRatio || 1;
  canvas.width = Math.max(1, Math.floor(rect.width * dpr));
  canvas.height = Math.max(1, Math.floor(rect.height * dpr));
  ctx.setTransform(dpr,0,0,dpr,0,0);
  renderAll();
}

function drawPattern() {
  const r = pattern.getBoundingClientRect();
  const width = r.width, height = r.height;
  pattern.setAttribute("viewBox", `0 0 ${width} ${height}`);
  pattern.innerHTML = "";

  const {W,H,twoH} = paperParams();
  const margin = 42;
  const s = Math.min((width - 2*margin)/W, (height - 2*margin)/twoH);
  const ox = (width - W*s)/2;
  const oy = height/2; // flat y=0 fold line

  function el(name) { return document.createElementNS("http://www.w3.org/2000/svg", name); }
  function line(x1,y1,x2,y2, stroke, dash="", lw=1.4) {
    const e = el("line");
    e.setAttribute("x1",x1); e.setAttribute("y1",y1);
    e.setAttribute("x2",x2); e.setAttribute("y2",y2);
    e.setAttribute("stroke",stroke);
    e.setAttribute("stroke-width",lw);
    e.setAttribute("stroke-linecap","round");
    if (dash) e.setAttribute("stroke-dasharray",dash);
    pattern.appendChild(e);
  }
  function rect(x,y,w,h,fill,stroke="#ddd",lw=1) {
    const e = el("rect");
    e.setAttribute("x",x); e.setAttribute("y",y);
    e.setAttribute("width",w); e.setAttribute("height",h);
    e.setAttribute("fill",fill);
    e.setAttribute("stroke",stroke);
    e.setAttribute("stroke-width",lw);
    pattern.appendChild(e);
  }
  function text(x,y,t,anchor="start") {
    const e = el("text");
    e.setAttribute("x",x); e.setAttribute("y",y);
    e.setAttribute("font-size","11");
    e.setAttribute("fill","#555");
    e.setAttribute("text-anchor",anchor);
    e.textContent = t;
    pattern.appendChild(e);
  }

  const paperTop = oy - H*s;
  const paperBottom = oy + H*s;

  rect(ox, paperTop, W*s, H*s, "rgba(255,255,250,.95)", "#bbb", 1);
  rect(ox, oy, W*s, H*s, "rgba(245,239,225,.95)", "#bbb", 1);
  rect(ox, paperTop, W*s, twoH*s, "transparent", "#888", 1.5);
  line(ox, oy, ox + W*s, oy, "#2874a6", "8 5", 2.2);

  text(ox + 4, oy - 8, "main fold y=0");
  text(ox + W*s + 6, paperTop + 4, "y=H");
  text(ox + W*s + 6, paperBottom, "y=-H → z=H");

  let x = ox;
  for (let i=0; i<design.widths.length; i++) {
    const stripW = design.widths[i] * s;
    const strip = design.strips[i];
    const cs = cumulative(strip);

    for (let j=0; j<strip.length; j++) {
      const t0 = cs[j], t1 = cs[j+1];
      const flatY0 = -H + t0;
      const flatY1 = -H + t1;
      const screenY1 = oy - flatY1*s;
      const h = (flatY1-flatY0)*s;
      const isHorizontal3D = (j % 2) === 0;
      rect(x, screenY1, stripW, h, isHorizontal3D ? "rgba(46,134,193,.13)" : "rgba(192,57,43,.11)", "none", 0);
    }

    for (let j=1; j<cs.length-1; j++) {
      const flatY = -H + cs[j];
      const yy = oy - flatY*s;
      line(x, yy, x+stripW, yy, "#2874a6", "6 5", 1.35);
    }

    line(x, paperTop, x, paperBottom, "#111", "", i===0 ? 2.0 : 1.3);
    x += stripW;
  }
  line(x, paperTop, x, paperBottom, "#111", "", 2.0);
  text(ox, paperBottom + 16, "Flat strip traversal starts at y=-H. In 3D that is z=H.");
}

function stripXPositions() {
  const xs = [0];
  for (const w of design.widths) xs.push(xs[xs.length-1] + w);
  return xs;
}

function buildQuads() {
  const {W,H} = paperParams();
  const xs = stripXPositions();
  const quads = [];

  // Literal 90° backing page. This stays visible behind/around the strip mesh.
  quads.push({
    pts: [[0,0,H],[W,0,H],[W,0,0],[0,0,0]],
    kind: "lowerSheet",
    axis: "sheet"
  });
  quads.push({
    pts: [[0,0,0],[W,0,0],[W,H,0],[0,H,0]],
    kind: "upperSheet",
    axis: "sheet"
  });

  // Alternating-segment strip mesh, extruded over strip width.
  for (let i=0; i<design.strips.length; i++) {
    const x0 = xs[i], x1 = xs[i+1];
    const strip = design.strips[i];

    let y = 0;
    let z = H;

    for (let j=0; j<strip.length; j++) {
      const L = strip[j];

      if ((j % 2) === 0) {
        // Horizontal 3D segment: Y fixed, Z decreases by L.
        const z2 = z - L;
        if (L > 1e-9) {
          quads.push({
            pts: [[x0,y,z],[x1,y,z],[x1,y,z2],[x0,y,z2]],
            kind: "strip",
            axis: "horizontal"
          });
        }
        z = z2;
      } else {
        // Vertical 3D segment: Z fixed, Y increases by L.
        const y2 = y + L;
        if (L > 1e-9) {
          quads.push({
            pts: [[x0,y,z],[x1,y,z],[x1,y2,z],[x0,y2,z]],
            kind: "strip",
            axis: "vertical"
          });
        }
        y = y2;
      }
    }
  }

  return quads;
}

function rotatePoint(p, rx, ry) {
  let [x,y,z] = p;
  const {W,H} = paperParams();

  // Centre around the folded corner region.
  x -= W/2;
  y -= H/3;
  z -= H/3;

  // rotate about X
  let c = Math.cos(rx), s = Math.sin(rx);
  let y1 = y*c - z*s;
  let z1 = y*s + z*c;
  y = y1; z = z1;

  // rotate about Y
  c = Math.cos(ry); s = Math.sin(ry);
  let x1 = x*c + z*s;
  let z2 = -x*s + z*c;
  x = x1; z = z2;

  return [x,y,z];
}

function project(p) {
  const r = canvas.getBoundingClientRect();
  const q = rotatePoint(p, cam.rx, cam.ry);
  const persp = 750 / (750 + q[2]*cam.zoom*0.035);
  return [
    r.width/2 + cam.panX + q[0]*cam.zoom*persp,
    r.height/2 + cam.panY - q[1]*cam.zoom*persp,
    q[2]
  ];
}

function drawPoly(pts, fill, stroke="#222", lw=1.05) {
  const ps = pts.map(project);
  ctx.beginPath();
  ctx.moveTo(ps[0][0], ps[0][1]);
  for (let i=1; i<ps.length; i++) ctx.lineTo(ps[i][0], ps[i][1]);
  ctx.closePath();
  ctx.fillStyle = fill;
  ctx.fill();
  ctx.strokeStyle = stroke;
  ctx.lineWidth = lw;
  ctx.stroke();
}

function drawLine3(a,b, stroke="#333", lw=1.4, dash=[]) {
  const pa = project(a), pb = project(b);
  ctx.save();
  ctx.setLineDash(dash);
  ctx.beginPath();
  ctx.moveTo(pa[0], pa[1]);
  ctx.lineTo(pb[0], pb[1]);
  ctx.strokeStyle = stroke;
  ctx.lineWidth = lw;
  ctx.stroke();
  ctx.restore();
}

function draw3D() {
  const r = canvas.getBoundingClientRect();
  ctx.clearRect(0,0,r.width,r.height);

  const quads = buildQuads();
  quads.forEach(q => {
    q.depth = q.pts.reduce((acc,p) => acc + rotatePoint(p, cam.rx, cam.ry)[2], 0) / q.pts.length;
  });
  quads.sort((a,b) => a.depth - b.depth);

  for (const q of quads) {
    let fill;
    if (q.kind === "lowerSheet") fill = "rgba(244,238,222,.45)";
    else if (q.kind === "upperSheet") fill = "rgba(255,255,250,.45)";
    else if (q.axis === "horizontal") fill = "rgba(46,134,193,.70)";
    else fill = "rgba(192,57,43,.65)";
    drawPoly(q.pts, fill, "#202020", q.kind.includes("Sheet") ? 0.9 : 1.25);
  }

  const {W,H} = paperParams();
  drawLine3([0,0,0],[W,0,0], "#2874a6", 2.0, [8,5]); // fold axis
  drawLine3([0,0,H],[W,0,H], "#555", 1.3, [5,5]);     // start edge
  drawLine3([0,0,0],[0,H,0], "#444", 1.2, []);
  drawLine3([0,0,0],[0,0,H], "#444", 1.2, []);

  ctx.fillStyle = "rgba(0,0,0,.62)";
  ctx.font = "12px -apple-system, BlinkMacSystemFont, sans-serif";
  ctx.fillText("Segment rule: horizontal in Y, then vertical in Z, alternating from the start edge z=H.", 10, r.height - 12);
}

// 3D canvas gestures
let pointers = new Map();
let lastSingle = null;
let lastPinch = null;

canvas.addEventListener("pointerdown", ev => {
  canvas.setPointerCapture(ev.pointerId);
  pointers.set(ev.pointerId, {x:ev.clientX, y:ev.clientY});
  if (pointers.size === 1) lastSingle = {x:ev.clientX, y:ev.clientY};
  if (pointers.size === 2) lastPinch = pinchState();
});
canvas.addEventListener("pointermove", ev => {
  if (!pointers.has(ev.pointerId)) return;
  pointers.set(ev.pointerId, {x:ev.clientX, y:ev.clientY});

  if (pointers.size === 1 && lastSingle) {
    const p = [...pointers.values()][0];
    const dx = p.x - lastSingle.x;
    const dy = p.y - lastSingle.y;
    cam.ry += dx * 0.008;
    cam.rx += dy * 0.008;
    cam.rx = Math.max(-1.5, Math.min(1.5, cam.rx));
    lastSingle = {x:p.x, y:p.y};
    draw3D();
  } else if (pointers.size === 2 && lastPinch) {
    const now = pinchState();
    cam.zoom *= now.dist / Math.max(1, lastPinch.dist);
    cam.zoom = Math.max(25, Math.min(260, cam.zoom));
    cam.panX += now.cx - lastPinch.cx;
    cam.panY += now.cy - lastPinch.cy;
    lastPinch = now;
    draw3D();
  }
});
canvas.addEventListener("pointerup", endCanvasPointer);
canvas.addEventListener("pointercancel", endCanvasPointer);

function endCanvasPointer(ev) {
  pointers.delete(ev.pointerId);
  lastSingle = pointers.size === 1 ? {...[...pointers.values()][0]} : null;
  lastPinch = pointers.size === 2 ? pinchState() : null;
}

function pinchState() {
  const ps = [...pointers.values()];
  const a = ps[0], b = ps[1];
  const dx = b.x-a.x, dy = b.y-a.y;
  return { dist: Math.hypot(dx,dy), cx: (a.x+b.x)/2, cy: (a.y+b.y)/2 };
}

// Resizable panes and collapse controls
const paneIds = ["paneData", "panePattern", "pane3d"];
let paneWeights = [34,33,33];

function applyPaneWeights() {
  const isNarrow = window.matchMedia("(max-width: 850px)").matches;
  const parts = [
    `minmax(48px, ${paneWeights[0]}fr)`,
    "8px",
    `minmax(48px, ${paneWeights[1]}fr)`,
    "8px",
    `minmax(48px, ${paneWeights[2]}fr)`
  ].join(" ");
  if (isNarrow) panes.style.gridTemplateRows = parts;
  else panes.style.gridTemplateColumns = parts;
  resize();
}

function resetPanes() {
  paneWeights = [34,33,33];
  for (const id of paneIds) {
    const p = document.getElementById(id);
    p.classList.remove("collapsed");
    const b = p.querySelector("button[data-collapse]");
    b.textContent = "hide";
  }
  applyPaneWeights();
}

let dragGutter = null;
document.querySelectorAll(".gutter").forEach(g => {
  g.addEventListener("pointerdown", ev => {
    g.setPointerCapture(ev.pointerId);
    dragGutter = {
      idx: Number(g.dataset.gutter),
      startX: ev.clientX,
      startY: ev.clientY,
      weights: paneWeights.slice()
    };
  });
  g.addEventListener("pointermove", ev => {
    if (!dragGutter) return;
    const isNarrow = window.matchMedia("(max-width: 850px)").matches;
    const delta = isNarrow ? ev.clientY - dragGutter.startY : ev.clientX - dragGutter.startX;
    const rect = panes.getBoundingClientRect();
    const totalPixels = isNarrow ? rect.height : rect.width;
    const deltaFr = delta / Math.max(1,totalPixels) * sum(dragGutter.weights);
    const i = dragGutter.idx;
    const a = Math.max(5, dragGutter.weights[i] + deltaFr);
    const b = Math.max(5, dragGutter.weights[i+1] - deltaFr);
    paneWeights = dragGutter.weights.slice();
    paneWeights[i] = a;
    paneWeights[i+1] = b;
    applyPaneWeights();
  });
  g.addEventListener("pointerup", () => { dragGutter = null; });
  g.addEventListener("pointercancel", () => { dragGutter = null; });
});

document.querySelectorAll("button[data-collapse]").forEach(b => {
  b.addEventListener("click", () => {
    const id = b.dataset.collapse;
    const idx = paneIds.indexOf(id);
    const pane = document.getElementById(id);
    const nowCollapsed = !pane.classList.contains("collapsed");
    pane.classList.toggle("collapsed", nowCollapsed);
    b.textContent = nowCollapsed ? "show" : "hide";
    paneWeights[idx] = nowCollapsed ? 5 : 30;
    applyPaneWeights();
  });
});

// Buttons
document.getElementById("exFolded").addEventListener("click", () => setExample("folded"));
document.getElementById("exStep").addEventListener("click", () => setExample("step"));
document.getElementById("ex1").addEventListener("click", () => setExample("richA"));
document.getElementById("ex2").addEventListener("click", () => setExample("richB"));
document.getElementById("apply").addEventListener("click", () => {
  const r = parseData();
  if (!r.ok) showStatus(r.error, true);
  else renderAll();
});
document.getElementById("resetPanes").addEventListener("click", resetPanes);

window.addEventListener("resize", applyPaneWeights);
