document.querySelectorAll("button[data-op]").forEach(b=>b.addEventListener("click",()=>{
  try{
    const a=vars[Number(selA.value)].value, bv=vars[Number(selB.value)].value, op=b.dataset.op;
    const result=opDesign(a,bv,op);
    addVar(`${op}(${vars[Number(selA.value)].name}, ${vars[Number(selB.value)].name})`,result);
    setOpStatus(`Added ${vars[selected].name}.`);
  }catch(e){setOpStatus(e.message,true);}
}));
window.addEventListener("resize",applyPaneWeights);

refreshUI();
applyPaneWeights();
